-- Seed new augments from backend/augments-updated.txt
-- Generated from the Lua table. Levels (level1/2/3) are intentionally omitted (no schema support yet).
-- Error/placeholder augments are seeded with enabled = false.
-- image is the asset key (no extension) when a matching *_large.webp exists in frontend/public/images/augments; otherwise NULL.
INSERT INTO augments (id, name, description, tier, image, notes, enabled) VALUES
(159, '???', 'Your[[File:Enemy Missing ping.png|30px|link=]]''''Enemy Missing'''' pings will cause you to launch a missile at the pinged location, exploding upon arrival to deal {{as|{{pp|100 to 400}}|magic damage}} {{as|(+ 10% of target''s ''''''missing'''''' health)}} {{as|magic damage}} to enemies struck, and {{tip|heal}} allied champions within for {{pp|50 to 200}} {{as|(+ 10% of target''s ''''''missing'''''' health)}}.', 'Prismatic', NULL, '*  No more than {{pp|2;4;6;7;7|type=[[Honor]] level|label=Ping count}} pings can be used within a 5-second period. Doing so restricts further use of pings for 6/12/16/20/24 seconds, refreshing and increasing per ping cast after the lockout ensues, and attempting to use pings during this time sends a warning message in the chat. The warning reads: <code>You must wait before issuing more pings.</code>
		** However, [[File:Enemy Missing ping.png|30px|link=]]''''Enemy Missing'''' pings may only be used 3 times each within 6 seconds at most. This incurs a separate cooldown from the global one, sending an alert to the player that reads: <code>You must wait before issuing more pings of that type.</code> Otherwise, the global ping cooldown is incurred as normal.', FALSE),
(160, '404 Augment Not Found', 'Gain 3 {{ii|Cappa Juice|hats}} per round.<br><br>''''{{sbc|Error:}} This augment is granted when an effect attempts to grant an invalid or duplicate augment.''''', 'Silver', NULL, NULL, FALSE),
(161, 'Adamant', '{{tip|immobilize|Immobilizing}} or {{tip|ground|grounding}} an enemy champion grants {{pp|2 to 10}} {{sti|{{as|''''''bonus'''''' armor}}}} and {{sti|{{as|''''''bonus'''''' magic resistance}}}} for 10 seconds, stacking up to 10 times for a total of {{pp|20 to 100}} ''''''bonus'''''' resistances, and refreshing on subsequent triggers ({{sti|5 seconds cooldown}} per {{tip|cast instance}}).', 'Silver', NULL, NULL, TRUE),
(162, 'Aim for the Head', 'Gain {{sti|{{as|25% critical strike chance}}}} and {{sti|{{as|25% ''''''bonus'''''' critical damage}}}}. Your {{sti|{{as|critical strike chance}}}} is capped at 50%. Convert a portion of excess {{sti|{{as|critical strike chance}}}} into {{sti|{{as|''''''bonus'''''' critical damage}}}}.', 'Gold', NULL, '* Aim for the Head nullifies the global, excess {{sti|{{as|critical strike chance}}}} to {{sti|{{as|adaptive force}}}} conversion.{{bug|2}}
        * Aim for the Head locks your {{sti|{{as|critical strike chance}}}} at 50%, preventing you from gaining more than {{sti|{{as|25% ''''''bonus'''''' critical damage}}}} from {{iis|Sword of the Divine}} {{nie|Excoriate}}.', TRUE),
(163, 'And My Axe!', '{{as|Automatically}} cast {{cai|Undertow|Olaf}}, throwing an axe at the nearest {{tip|sight|visible}} enemy champion within 950 units. Enemies hit are dealt {{as|physical damage}}, {{tip|slow|slowed}} for {{fd|1.5}} seconds and have 20% reduced {{sti|{{as|armor}}}} and {{sti|{{as|magic resistance}}}} for 4 seconds ({{sti|12 seconds cooldown}}). The caster can pick up the axe by walking within 250 units of its landing location, reducing the effect''s {{sti|''''''current'''''' cooldown}} to {{fd|1.5}} seconds or immediately resetting it if that has already elapsed. The axe has a width of {{tip|er|icononly=true}} 180 units and can additionally hit targets in a {{tip|cr|icononly=true}} 100-unit radius upon landing.', 'Gold', 'andmyaxe_large', NULL, TRUE),
(164, 'Augment 405', 'Gain 5% increased damage per {{ii|Cappa Juice|hat}}.<br><br>''''{{sbc|Error:}} This augment is granted when Parasitic or Symbiotic Mutation attempts to grant a duplicate augment, including itself.''''{{citation needed}}', 'Prismatic', 'augment405_large', NULL, FALSE),
(165, 'Augmented Power', 'Your augments and [[items]] deal ''''''increased'''''' damage.', 'Silver', NULL, NULL, TRUE),
(166, 'Big Dragon Energy', 'Start combat with full {{tip|Fury|{{as|Dragon Fury}}}} and it no longer decays while in {{ai|Dragon''s Descent|Shyvana|Dragon Form}}.<br><br>While in {{ai|Dragon''s Descent|Shyvana|Dragon Form}} {{ai|Emberstrike|Shyvana}}''s final strike does 200% {{tip|true damage}}.<br><br>''''This augment is only available for {{ci|Shyvana}}.''''', 'Gold', NULL, NULL, TRUE),
(167, 'Bodyguard', '{{tip|dash|Dashing}} or {{tip|blink|blinking}} grants a {{pp|35 to 250}} {{tip|shield|base shield}}, increased by {{pp|125-35 to 500-250|10 to 80 by 10|label1=Seconds|type=the source spell''s ''''''base'''''' cooldown|formula=Linear interpolation between [ 125{{minus}}(35 base) ] minimum shield at 10 second base cooldown (before haste) of the dash or blink used, and [ 500{{minus}}(250 base) ] maximum shield at 80 seconds.}} for {{fd|2.5}} seconds ({{sti|{{fd|0.1}} seconds cooldown}} per {{tip|cast instance}}; {{sti|3 seconds cooldown}} per source). Any allies you pass through are also granted the same shield you have generated ({{tip|cr|icononly=true}} 200 radius of collision). Up to 5 shields generated can stack on a given champion, refreshing with each generation.', 'Gold', 'bodyguard_large', NULL, TRUE),
(168, 'Bounce of the Poro King', 'Replace {{si|Flee}} with [[File:Bounce of the Poro King.png|20px|link=]] ''''''Bounce of the Poro King''''''.<br><br>{{sbc|Bounce of the Poro King:}} Transform into the [[File:ProfileIcon0748 Icon of the Poro King.png|20px|link=]] ''''''Poro King'''''' for 3 seconds, during which you gain 70% damage reduction, {{sti|{{as|40% ''''''bonus'''''' movement speed}}}}, {{tip|cc-immune|crowd control immunity}}, and {{tip|ghosting}}, but become {{tip|lockout|unable}} to declare basic attacks and cast abilities. Upon transformation, you also {{tip|cleanse}} yourself of all {{tip|crowd control}}. While transformed, you bounce up and down every 1 second, with each bounce dealing {{as|{{pp|100 to 700}}|physical damage}} {{as|physical damage}} to nearby enemy champions and {{tip|airborne|knocking them back}} upon landing. An enemy champion can be hit by multiple bounces, but ones beyond the first do not apply the knock back (30 second cooldown).', 'Prismatic', NULL, NULL, TRUE),
(169, 'Bravest of the Brave', 'The tier of all future augment offerings is increased. If the offered augment is already prismatic, then you gain a certain amount of {{g|gold}} instead.', 'Silver', 'bravestofthebrave_large', NULL, TRUE),
(170, 'Bread Sandwich', 'Gain {{sti|{{as|ability haste}}}}. Casting an ability grants you {{sti|{{as|40% ''''''bonus'''''' movement speed}}}} for 2 seconds.', 'Prismatic', NULL, '* This augment isn''t available for choice. Instead, it can only be obtained when you gather all of {{aug|ar|Bread And Butter}}, {{aug|ar|Bread And Cheese}} and {{aug|ar|Bread And Jam}}.
		* Upon synthesizing this augment, those individual Bread augments will be removed from your augment slots, thus allowing you to gain further augment selections.
		* The initial level at the instant you gain this augment is determined by the levels of the ''''ingredient bread'''' augments.', TRUE),
(171, 'Calculated Risk', 'Your rerolls are consumed by this effect and you can no longer gain any rerolls for the remainder of the game.<br><ul><li>If you have more than 2 augments, selecting this augment immediately offers a Gold-tier augment selection screen.</li><li>If you have at most 2 augments, selecting this augment immediately offers a Prismatic-tier augment selection screen.</li></ul>', 'Silver', NULL, NULL, TRUE),
(172, 'Cerberus', 'Gain the {{ri|Hail of Blades}} and {{ri|Press the Attack}} keystone runes.<br><br>''''See [[Arena#Runes]] for Arena-specific overrides on these runes.''''', 'Prismatic', 'cerberus_large', NULL, TRUE),
(173, 'Chroma Flux', NULL, 'Prismatic', NULL, NULL, TRUE),
(174, 'Clown College', 'Gain {{cis|Shaco}} {{ai|Backstab|Shaco}}, {{ai|Deceive|Shaco}} and {{ais|Hallucinate|Shaco}} explosion. Replaces {{si|Flee}} with ''''{{ai|Deceive|Shaco}}''''.<br><br>[[File:Backstab.png|20px|link=]] {{sbc|Passive - Backstab:}} Your basic attacks deal {{as|{{pp|20 to 35}}|physical damage}} {{as|(+ 50% ''''''bonus'''''' AD)}} {{as|(+ 35% AP)}} {{ccs|{{as|''''''bonus'''''' physical damage}}|physical}} on-hit when hitting an enemy from behind.<br><br>[[File:Deceive.png|20px|link=]] {{sbc|Active - Deceive:}} Become {{tip|invisible}} for up to 3 seconds and {{tip|blink}} to the target location within 400 units after a {{fd|0.125}}-second delay. Your next basic attack while in stealth deals {{as|100|physical damage}} {{as|(+ 150% ''''''bonus'''''' AD)}} {{as|(+ 55% AP)}} {{as|''''''bonus'''''' physical damage}}, increased to{{ft|(155% + {{as|crit damage}}) damage|{{as|100 {{times}} (1.55 + {{as|crit damage}})|physical damage}} {{as|(+ 150% {{times}} (1.55 + {{as|crit damage}}) ''''''bonus'''''' AD)}} {{as|(+ 55% {{times}} (1.55 + {{as|crit damage}}) AP)}} {{as|''''''bonus'''''' physical damage}}}} if [[File:Backstab.png|20px|link=]] ''''Backstab'''' was applied ({{sti|15 seconds cooldown}}).<br><br>[[File:Hallucinate.png|20px|link=]] {{sbc|Passive - Hallucinate:}} Upon your death, release an explosion in a {{tip|cr|icononly=true}} 350 radius of your death location, dealing {{as|25% of target''s ''''''maximum'''''' health}} {{as|true damage}} to enemies within and {{tip|fear|fearing}} them for 1 second. ''''This effect cannot award victory to the user if they are the last one standing on their team.''''', 'Prismatic', 'clowncollege_large', NULL, TRUE),
(175, 'Combination Fried Rice', 'Your abilities gains increased damage, {{tip|heal|healing}} and {{tip|shield|shielding}}. However, you lose {{sti|{{as|50 ability haste}}}}. Casting an ability grants you {{sti|{{as|40% ''''''bonus'''''' movement speed}}}} for 2 seconds.', 'Prismatic', NULL, '* This augment isn''t available for choice. Instead, it can only be obtained when you gather all of {{aug|ar|Rice And Chicken}}, {{aug|ar|Rice And Fish}} and {{aug|ar|Rice And Pork}}.
		* Upon synthesizing this augment, those individual Rice augments will be removed from your augment slots, thus allowing you to gain further augment selections.
		* The initial level at the instant you gain this augment is determined by the levels of the ''''ingredient rice'''' augments.', TRUE),
(176, 'Crack Open That Egg', 'Your {{tip|shield|shields}} detonate upon expiration, creating an explosion that deals {{as|magic damage}} equal to a multiple of the shield to nearby enemies.', 'Silver', NULL, NULL, TRUE),
(177, 'Critical Rhythm', 'Your {{tip|critical strikes}} grant you {{sti|{{as|6% ''''''bonus'''''' attack speed}}}} for 6 seconds, stacking up to several times. Additionally, gain {{sti|{{as|25% critical strike chance}}}}.', 'Gold', NULL, NULL, TRUE),
(178, 'Dark Blessing', 'The next instance of {{tip|healing}} or {{tip|shielding}} you grant to an ally generates {{as|5 Cursed Power}} ({{sti|{{fd|1.5}} seconds cooldown}}). You can generate up to {{as|30|Curse}} (+ {{as|20|Curse}}{{times}}number of Curse augments equipped by you and your teammate) {{as|Cursed Power}} per round. Permanently gain {{sti|{{as|ability haste}}}}	equal to {{as|a percentage of your Cursed Power}}.', 'Gold', 'darkblessing_large', NULL, TRUE),
(179, 'Deathtouch', 'Basic attacks against {{tip|champions}} {{tip|on-hit}} generate {{as|2 Cursed Power}}. You can generate up to {{as|30|Curse}} (+ {{as|20|Curse}}{{times}}number of Curse augments equipped by you and your teammate) {{as|Cursed Power}} per round. Permanently gain {{as|''''''bonus'''''' magic damage}} {{tip|on-hit}} equal to {{as|a percentage of your Cursed Power}}.', 'Gold', 'deathtouch_large', NULL, TRUE),
(180, 'Demonic Clasp', 'Replaces {{si|Flee}} with ''''{{si|Demonic Clasp}}''''.<br><br>[[File:Demonic Clasp augment spell.png|20px|link=]] {{sbc|Demonic Clasp:}} {{#invoke:SpellData|geteffect|Demonic Clasp}}', 'Gold', NULL, NULL, TRUE),
(181, 'Desecrator', '{{tip|immobilize|Immobilizing}} an enemy champion generates {{as|10 Cursed Power}}. You can generate up to {{as|30|Curse}} (+ {{as|20|Curse}}{{times}}number of Curse augments equipped by you and your teammate) {{as|Cursed Power}} per round. Permanently gain {{sti|{{as|''''''bonus'''''' armor}}}} and {{sti|{{as|''''''bonus'''''' magic resistance}}}} equal to {{as|a percentage of your Cursed Power}}.', 'Silver', 'desecrator_large', NULL, TRUE),
(182, 'Despoil', '{{tip|Dash|Dashing}} or {{tip|blink|blinking}} near an enemy champion generates {{as|2 Cursed Power}}. You can generate up to {{as|30|Curse}} (+ {{as|20|Curse}}{{times}}number of Curse augments equipped by you and your teammate) {{as|Cursed Power}} per round. Permanently gain {{sti|{{as|''''''bonus'''''' movement speed}}}} equal to {{as|10% of your Cursed Power}}.', 'Silver', NULL, NULL, TRUE),
(183, 'Devil on Your Shoulder', 'Forge a pact with {{csl|Teemo|Little Devil}}, who {{tip|health resource|drains}} {{as|{{fd|0.5%}} of your ''''''current'''''' health}} every second, increased to {{as|5%|hp}} if there are enemy champions within 1000 units. In return, you deal {{as|''''''bonus'''''' true damage}} and your basic attacks and abilities summon a ''''Life Remnant'''' nearby for 5 seconds ({{fd|0.75}}-second spawn cooldown). You can absorb a ''''Life Remnant'''' by moving over it, {{tip|heal|healing}} you for {{pp|100 to 250}} {{as|(+ 60% ''''''bonus'''''' AD)}} {{as|(+ 30% AP)}} and granting you {{sti|{{as|''''''bonus'''''' movement speed}}}}.', 'Prismatic', NULL, NULL, TRUE),
(184, 'Divine Intervention', '{{as|Automatically}} cast {{cai|Cosmic Radiance|Taric}}, calling down a protective star upon you that descends over {{fd|2.5}} seconds. Afterwards, you and your teammate within {{tip|cr|icononly=true}} 400 units become {{tip|invulnerable}} for {{fd|2.5}} seconds. This effect activates {{tt|{{ap|12-2.5}} seconds after|Unaffected by ability haste.}} the start of the ''''Combat Phase''''.', 'Gold', NULL, NULL, TRUE),
(185, 'Donation', 'Gain {{g|1750}} upon acquiring this augment.', 'Gold', NULL, '* This effect will repeat when you acquire this augment repeatedly through ''''''Symbiotic Mutation''''''', TRUE),
(186, 'Doomsayer', 'The next instance of [[ability damage]] against enemy champions generates {{as|2 Cursed Power}} ({{sti|3 seconds cooldown}}). You can generate up to {{as|30|Curse}} (+ {{as|20|Curse}}{{times}}number of Curse augments equipped by you and your teammate) {{as|Cursed Power}} per round. Permanently gain {{tip|adaptive force}} equal to {{as|a percentage of your Cursed Power}}.', 'Prismatic', 'doomsayer_large', NULL, TRUE),
(187, 'Double Tap', 'Basic attacks that {{tip|critical strike|critically strike}} apply {{tip|on-hit}} effects an additional time. Additionally, gain {{sti|{{as|25% critical strike chance}}}}.', 'Gold', NULL, NULL, TRUE),
(188, 'Dreadbringer', 'For every {{fd|0.5}} seconds that you are within 500 units of an enemy champion, generate {{as|1 Cursed Power}} for each one in range. You can generate up to {{as|30|Curse}} (+ {{as|20|Curse}}{{times}}number of Curse augments equipped by you and your teammate) {{as|Cursed Power}} per round. Permanently gain {{sti|{{as|''''''bonus'''''' health}}}} equal to {{as|a percentage of your Cursed Power}}.', 'Prismatic', NULL, NULL, TRUE),
(189, 'Energetic', 'Gain increased {{tip|Energized}} stack generation. Upon triggering an {{tip|Energized}} effect, fire a bolt that deals {{as|true damage}} equal to {{as|{{fd|0.3}}% of the target''s ''''''maximum'''''' health}}.', 'Silver', 'energetic_large', NULL, TRUE),
(190, 'Escape Plan', 'Upon dropping below {{sti|{{as|35% health}}}}, gain a {{tip|shield}} for {{as|65% of your ''''''maximum'''''' health}}, {{sti|{{as|150% ''''''bonus'''''' movement speed}}}}, and {{sti|reduced size}} ({{sti|75 seconds cooldown}}). These effects all decay over 5 seconds.', 'Silver', NULL, NULL, TRUE),
(191, 'Final Form', 'Casting your ultimate ability empowers you for 5 seconds, causing you to gain a {{tip|shield}} based on {{sti|{{as|your ''''''maximum'''''' health}}}}, {{sti|{{as|omnivamp}}}}, and {{sti|{{as|30% ''''''bonus'''''' movement speed}}}} for the duration ({{sti|20 seconds cooldown}}).', 'Prismatic', NULL, NULL, TRUE),
(192, 'Firefox', '{{as|Automatically}} cast {{cai|Fox-Fire|Ahri}}, gaining {{sti|{{as|50% ''''''bonus'''''' movement speed}}}} that decays over 2 seconds and conjuring 3 flames that orbit you clockwise for up to {{fd|2.5}} seconds at a radius of {{tip|cr|icononly=true}} 150 units. The flames will {{tt|fly toward|On a 0.25-second delay after acquisition}} the nearest {{tip|sight|visible}} enemy champion within {{tip|cr|icononly=true}} 550 units, dealing {{pp|35 to 160}} {{as|(+ 25% ''''''bonus'''''' AD}} {{as|(+ 25% AP)}} {{tip|magic damage}}, reduced to {{ft|{{pp|35*0.3 to 160*0.3}} {{as|(+ {{ap|25*0.3}}% ''''''bonus'''''' AD}} {{as|(+ {{ap|25*0.3}}% AP)}}|30% of the original damage}} for enemies hit by subsequent flames from the same cast ({{sti|7 seconds cooldown}}).', 'Silver', NULL, NULL, TRUE),
(193, 'Get Excited!', 'Scoring a champion {{tip|takedown}} grants you {{sti|{{as|''''''bonus'''''' movement speed}}}} and {{sti|{{as|15% ''''''bonus'''''' attack speed}}}} for 6 seconds.', 'Gold', NULL, NULL, TRUE),
(194, 'Glass Cannon', 'You gain a [[Health#Health_threshold|health threshold]] equal to {{sti|{{as|70% ''''''maximum'''''' health}}}} which cannot be {{tt|modified|By increases or decreases to maximum health}} nor {{tt|exceeded|By healing and health regeneration}} by any means. In return, you deal {{as|''''''bonus'''''' true damage}} equal to a percentage of all of the damage you deal {{tt|pre-mitigation|Damage calculated before modifiers}}.', 'Prismatic', NULL, NULL, TRUE),
(195, 'Grevious Venom', 'Dealing damage to an enemy champion inflicts them with venom for 3 seconds, reducing any {{tip|shield|shields}} they gain within the duration by 50%, and applies {{tip|Grievous Wounds}} for the same duration.<br><br>If the target had a shield at the time of application and was not already afflicted by the venom, the strength of all active shields on them is reduced by 50%.<br><br>If the target {{tip|heal|heals}} for a total amount that is over {{sti|{{as|60% of their ''''''maximum'''''' health}}}} while continuously afflicted with {{tip|Grievous Wounds}}, the strength of the healing reduction is increased to 80%.<br><br>''''The shield reduction does not affect [[Shield#Magic shields|magic damage shields]].''''', 'Silver', NULL, NULL, TRUE),
(196, 'Growth Spurt', 'Replaces {{si|Flee}} with [[File:Growth Spurt.png|20px|link=]] ''''''Growth Spurt''''''.<br><br>{{sbc|Growth Spurt:}} Enlarge yourself, causing you to {{tip|airborne|knock up}} enemies within {{tip|cr|icononly=true}} 400 units for 1 second. For a duration, you also gain {{as|''''''bonus'''''' health}} and 50% increased size (45 second cooldown).', 'Gold', NULL, NULL, TRUE),
(197, 'Hat Trick', 'Gain 3 {{ii|Cappa Juice|hats}} upon selecting this augment and permanently reduce the cost of {{ii|Cappa Juice}} in your shop by {{g|350}}. Upon dropping below {{sti|{{as|30% of your ''''''maximum'''''' health}}}}, gain {{sti|{{as|35% ''''''total'''''' movement speed}}}} and a {{pp|300 to 500}} {{as|(+ 75% ''''''bonus'''''' movement speed)}} {{tip|shield}} for 3 seconds, but lose one hat every time this effect activates ({{sti|3 seconds cooldown}}).', 'Gold', 'hattrick_large', NULL, TRUE),
(198, 'Hextech Soul', 'Grants the {{bi|Hextech Dragon Soul}}, or a different {{bi|Dragon Soul}} if you already have it.', 'Silver', NULL, NULL, TRUE),
(199, 'Hive Mind', 'Start each round with a number of ''''Bees'''' following you; gain an additional ''''Bee'''' for each hit you or your teammate perform against {{ui|Power Flower|Power Flowers}}, up to a maximum of 8 ''''Bees''''. For each instance of damage dealt to an enemy champion you send a ''''Bee'''' to them, dealing {{ft|{{as|{{pp|40 to 100}}|magic damage}} {{as|(+ 20% ''''''bonus'''''' AD)}} {{as|(+ 20% AP)}} {{as|magic damage}} over 2 seconds|{{as|{{pp|40/8 to 100/8}}|magic damage}} {{as|(+ {{ap|20/8}}% ''''''bonus'''''' AD)}} {{as|(+ {{ap|20/8}}% AP)}} {{as|magic damage}} every {{fd|0.25}} seconds}} on arrival. ''''Bees'''' return to you 6 seconds after being sent off.', 'Prismatic', NULL, '* A special "+Bee" indicator accompanies gaining a ''''Bee'''' which displays over the user''s model.
		** This is only visible to the user.', TRUE),
(200, 'Hybrid', 'Damaging {{tip|basic attacks|attacks}} {{tip|on-hit}} grant you increased damage on your next damaging {{tip|champion ability}}. Damaging {{tip|champion ability|champion abilities|nolink=true}} grant you increased damage on your next {{tip|basic attack|attack|nolink=true}} {{tip|on-hit}}. This effect does not stack.', 'Gold', 'hybrid_large', NULL, TRUE),
(201, 'Juice Press', 'The price of {{ii|Juice of Haste}}, {{ii|Juice of Power}} and {{ii|Juice of Vitality}} in your and your teammate''s shop is reduced by 50% ({{g|{{ap|500*0.5}}}}). Juices that you and your teammate consume grant additional effects.<ul><li>{{ii|Cappa Juice}}: 1 additional {{ii|Cappa Juice|hat}}.</li><li>{{ii|Juice of Haste}}: {{sti|{{as|20% ''''''bonus'''''' movement speed}}}}.</li><li>{{ii|Juice of Power}}: {{sti|{{as|15% armor penetration}}}} and {{sti|{{as|15% magic penetration}}}}.</li><li>{{ii|Juice of Vitality}}: {{sti|{{as|25% heal and shield power}}}}.</li></ul><br><br>''''Removed since [[V26.09]].''''', 'Silver', 'juicepress_large', NULL, TRUE),
(202, 'Juiced', 'Basic attacks {{tip|on-hit}} against enemy champions consume {{sti|{{as|{{fd|2.5}}% of your ''''''maximum'''''' mana}}}} to deal {{as|''''''bonus'''''' magic damage}} based on {{sti|{{as|your ''''''maximum'''''' mana}}}}. This damage can {{tip|critically strike}} for {{critical damage|100}} ''''''bonus'''''' damage.', 'Silver', NULL, NULL, TRUE),
(203, 'Kill Secured', 'Gain {{sti|{{as|60% ''''''bonus'''''' movement speed}}}} towards enemy champions below {{sti|{{as|40% of their ''''''maximum'''''' health}}}}.', 'Silver', NULL, NULL, TRUE),
(204, 'Leg Day', 'Gain {{sti|{{as|''''''bonus'''''' movement speed}}}} and {{tip|slow resist}}.', 'Silver', 'legday_large', NULL, TRUE),
(205, 'Magical Girl', 'Each round, a star falls over 15 seconds. You can pick up the star by walking within {{tip|cr|200}} units of its landing location. After picking it up, you transform into a ''''''Magical Girl'''''', gain {{tip|adaptive force}} and a {{tip|shield}}. Upon transformation, you {{tip|airborne|knock back}} nearby enemies to {{tip|cr|1000}} units from you, and cause them to dance for 2 seconds, but granting them {{tip|invulnerability}} for the same duration.<br>As a Magical Girl, every 5 to 10 seconds (based on the number of enemies within {{tip|cr|700}} units from you), several stars fall from the sky striking around you and each of your enemies, dealing {{pp|100 to 500}} {{as|(+ 25% AP)}} {{as|magic damage}} to those hit.', 'Prismatic', NULL, NULL, TRUE),
(206, 'Mercy', 'When your team triggers [[Arena#Combo_Breaker|Combo Breaker]] by {{tip|immobilize|immobilizing}} an enemy champion for 4 seconds out of the last 7 seconds, you become ''''''enraged'''''' and your next {{tip|immobilize|immobilizing}} effects deal {{as|magic damage}} based on {{sti|{{as|your ''''''maximum'''''' health}}}} to the target. This effect resets every round.', 'Gold', NULL, NULL, TRUE),
(207, 'Multitool', 'Gain the {{ii|Multitool}} in your inventory. At each Shopping Phase, you can choose 1 out of 5 random items on the top of your inventory for {{ii|Multitool}} to transform into. {{ii|Multitool}} can provide prismatic items after the 4th round.<br><br>''''Removed since [[V26.09]].''''', 'Gold', 'multitool_large', NULL, TRUE),
(208, 'Null', 'No effect.<br><br>''''{{sbc|Error:}} This augment is ''''''only'''''' granted when the Parasitic Mutation augment has failed to copy an augment.''''', 'Prismatic', NULL, NULL, TRUE),
(209, 'Numb to Pain', 'Gain {{iis|Death''s Dance}} {{nie|Ignore Pain}}.<br><br>{{sbc|Ignore Pain:}} Reduce some {{tt|post-mitigation damage|Damage calculated after modifiers}} received and instead store it to successively take it as {{sti|{{as|true damage}}}} over 6 seconds, dealing a sixth of the stored damage each second.', 'Silver', 'numbtopain_large', NULL, TRUE),
(210, 'Ominous Pact', 'Your abilities now have a {{tip|health resource|health cost}} of {{sti|{{as|5% ''''''current'''''' health}}}} to cast them. In return, you gain {{sti|{{as|ability power}}}}, {{sti|{{as|''''''bonus'''''' movement speed}}}} and {{sti|{{as|omnivamp}}}} based on your {{sti|{{as|''''''missing'''''' health}}}}.', 'Prismatic', NULL, NULL, TRUE),
(211, 'Overflow', 'Your abilities'' {{sti|{{as|mana}}}} costs are doubled, but you also gain increased damage as well as self and outgoing {{tip|heal|healing}} and {{tip|shield|shielding}}, based on {{sti|{{as|your ''''''maximum'''''' mana}}}}.', 'Gold', 'overflow_large', NULL, TRUE),
(212, 'Pandora''s Box', 'Your current augments transform into an equal number of completely random Prismatic ones.', 'Prismatic', NULL, NULL, TRUE),
(213, 'Panic Room', 'Upon taking fatal damage for the first time, you become {{tip|untargetable}}, transforming into a wisp, and are restored to {{sti|{{as|a portion of your ''''''maximum'''''' health}}}}. After 1 second, {{tip|dash}} to a random location on the map 1500â3000 units away at 3500 unit/s speed and become targetable again upon arrival. The target location is always inside the Ring of Fire and up to 1500 units away from its edge.', 'Silver', NULL, NULL, TRUE),
(214, 'Parasitic Mutation', 'Copy a random [[File:Augment.png|20px|icononly=true]] augment from either champion on the enemy team when the ''''Combat Phase'''' starts, with the copied augment changing every round.', 'Silver', 'parasiticmutation_large', NULL, TRUE),
(215, 'Pinball', 'Replaces {{si|Flee}} with {{si|Mark}}. Your {{si|Mark}} is empowered to instead throw a pinball, which deals {{as|{{pp|100 to 500}} ''''''bonus'''''' true damage}} and ricochets off of terrain that it collides with. Each time the pinball ricochets, its remaining travel distance is reset, it increases in {{sti|size|radius}} by 25%, deals 20% increased damage, and reduces {{sis|Mark}} remaining cooldown by {{sti|cooldown|30% of its ''''''total''''''}}. The pinball can ricochet up to 4 times, for a maximum radius increase of 100% and a damage increase of 80%. Additionally, your {{si|Mark}} gains {{sti|{{as|50 ability haste}}}}.', 'Gold', NULL, NULL, TRUE),
(216, 'Protein Shake', 'Gain {{sti|hsp|{{as|25%|heal and shield power}}}} {{as|(+ 35% per 100 ''''''bonus'''''' armor)}} {{as|(+ 35% per 100 ''''''bonus'''''' magic resistance)}} {{as|heal and shield power}}.', 'Prismatic', NULL, NULL, TRUE),
(217, 'Purist - Caster', 'Convert ''''''all'''''' of your {{sti|{{as|''''''bonus'''''' attack speed}}}} into {{sti|{{as|ability haste}}}} at a rate of {{sti|{{as|{{fd|0.65}} ability haste}}}} per {{sti|{{as|1% ''''''bonus'''''' attack speed}}}}. Additionally, your abilities'' ''''''total'''''' cooldowns are reduced by {{sti|cooldown reduction|10%}}.', 'Silver', NULL, '* {{sti|Maximum cooldown reduction}}: 500 Ã· (500 + 100) + 10% â‰ˆ {{fd|93.3}}%.', TRUE),
(218, 'Quest: Icathia''s Fall', 'Gain {{ii|Bami''s Cinder}}. You can now purchase {{ii|Hollow Radiance}} and {{ii|Sunfire Aegis}} in spite of the item limit imposed by {{nie|Immolate}}.<br><br>{{sbc|Quest:}} Obtain {{ii|Hollow Radiance}} and {{ii|Sunfire Aegis}}.<br><br>{{sbc|Reward:}} Upon completing your {{sbc|Quest}}, convert the items you obtained for the quest into {{ii|Void Immolation}}.<br><br>''''{{ii|Void Immolation}} counts as 2 {{as|Burn}} effect sources.', 'Prismatic', NULL, NULL, TRUE),
(219, 'Quest: Mad Hatter', '{{sbc|Quest:}} Wear 10 {{ii|Cappa Juice|hats}} simultaneously.<br><br>{{sbc|Reward:}} For each hat currently worn, gain {{adaptive|12}}, {{sti|{{as|8 ''''''bonus'''''' armor}}}}, {{sti|{{as|8 ''''''bonus'''''' magic resistance}}}}, {{sti|{{as|3% tenacity}}}} and {{sti|{{as|4 ''''''bonus'''''' movement speed}}}}. However, you now lose half your hats upon losing a round.<br><br>''''If the requirements are fulfilled at any point during a Combat Phase, only grants the rewards ''''''after the end'''''' of the current round. Rewards cannot be earned mid-combat.''''', 'Gold', NULL, NULL, TRUE),
(220, 'Quest: Rite of the Forge God', '{{sbc|Quest:}} Purchase 2 Item Anvils ({{ii|Prismatic Item|icononly=true}} / {{ii|Legendary Assassin Item|icononly=true}}{{ii|Legendary Fighter Item|icononly=true}}{{ii|Legendary Mage Item|icononly=true}}{{ii|Legendary Marksman Item|icononly=true}}{{ii|Legendary Support Item|icononly=true}}{{ii|Legendary Tank Item|icononly=true}}).<br><br>{{sbc|Reward:}} All of your items will become {{ai|Living Forge|Ornn|Masterwork}}, increasing their stats by 35%.', 'Prismatic', NULL, '* Stats from item passives won''t be amplified, like {{iis|Demon King''s Crown}} ''''Supremacy'''', {{iis|Dragonheart}} ''''Inner Flame'''', {{iis|Twin Mask}} ''''Unanimity'''', etc.', TRUE),
(221, 'Quest: Three Sacred Treasures', '{{sbc|Quest:}} Possess {{ii|Hextech Gunblade}}, {{ii|Infinity Edge}} and {{ii|Perplexity}}.<br><br>{{sbc|Reward:}} Attacks now fire in a narrow straight line, damaging all enemies within for {{as|60% AP}} {{as|physical damage}} and {{as|75% AD}} {{as|magic damage}} and applying {{tip|on-hit}} effects twice.<br><br>''''This augment is only available for {{ci|Yunara}} and can only be offered during the first {{tt|two|This needs further verification in the new version}} rounds where [[Arena#Shop_Phase|Augment selection is available]].''''', 'Gold', NULL, NULL, TRUE),
(222, 'Rags to Riches', 'Gain {{g|2500}} once this [[File:Augment.png|20px|icononly=true]] augment is removed or replaced.', 'Silver', NULL, NULL, TRUE),
(223, 'Rice And Chicken', 'Your champion''s first basic ability ''''(Q)'''' gains increased damage and increased {{tip|heal|Healing}} and {{tip|shield|Shielding}}, but loses {{sti|{{as|50 ability haste}}}}.', 'Gold', NULL, NULL, TRUE),
(224, 'Rice And Fish', 'Your champion''s second basic ability ''''(W)'''' gains increased damage and increased {{tip|heal|Healing}} and {{tip|shield|Shielding}}, but loses {{sti|{{as|50 ability haste}}}}.', 'Gold', NULL, NULL, TRUE),
(225, 'Rice And Pork', 'Your champion''s third basic ability ''''(E)'''' gains increased damage and increased {{tip|heal|Healing}} and {{tip|shield|Shielding}}, but loses {{sti|{{as|50 ability haste}}}}.', 'Gold', NULL, NULL, TRUE),
(226, 'Righteous Fury', 'Self and outgoing {{tip|healing}} or {{tip|shielding}} grants you increased ability damage ({{sti|3 seconds cooldown}}). This effect can only occur once per cast instance, stacks infinitely and lasts until the end of the current round phase.', 'Prismatic', NULL, NULL, TRUE),
(227, 'Scavenger', 'Increase your augment count to 6. When you defeat a team, a selection screen of their augments will open in the shopping phase of the next round. From now, ''''Augment Selections'''' only provide ''''''Augment Level Ups''''''.<br>If none of their augments are applicable to you, you''ll gain {{g|500}} instead.', 'Gold', NULL, NULL, TRUE),
(228, 'Shrink Engine', 'Scoring a champion {{tip|takedown}} generates a stack, stacking infinitely. For each stack, gain {{sti|{{as|8 ability haste}}}} and {{sti|{{as|1% ''''''bonus'''''' movement speed}}}}, and reduce your {{sti|size}} by 4%. Lose 50% of stacks on death.<br><br>''''Size reduction is capped at 80% (20 stacks).''''', 'Gold', NULL, NULL, TRUE),
(229, 'Silver Spoon', 'For each [[File:Augment.png|20px|icononly=true]] ''''''Silver'''''' augment you have, gain increased damage.', 'Silver', NULL, NULL, TRUE),
(230, 'Slow and Steady', 'Your {{sti|{{as|''''''base'''''' attack speed}}}} is set to a static amount of {{as|{{fd|0.65}}|as}} and your attack rate no longer benefits from any source of attack speed bonuses. In return, you convert all {{sti|{{as|''''''bonus'''''' attack speed}}}} into {{sti|{{as|''''''bonus'''''' attack damage}}}}.', 'Gold', 'slowandsteady_large', NULL, TRUE),
(231, 'Speed Demon', 'Whenever you damage an enemy champion with an ability, gain {{sti|{{as|''''''bonus'''''' movement speed}}}} decaying over {{fd|0.75}} seconds.', 'Silver', NULL, NULL, TRUE),
(232, 'Spellcraft', 'Replaces {{si|Flee}} with ''''{{si|Spellcraft}}''''.<br><br>[[File:Spellcraft augment spell.png|20px|link=]] {{sbc|Spellcraft:}} {{#invoke:SpellData|geteffect|Spellcraft}}', 'Prismatic', NULL, NULL, TRUE),
(233, 'Spin Me Right Round', 'Replaces {{si|Flee}} with ''''{{cai|Heroic Swing|Akshan}}''''.<br><br>{{sbc|Heroic Swing - Active:}} You can activate ''''Heroic Swing'''' three times before the ability goes on cooldown, and you can use the third cast only after {{fd|0.5}} seconds of the second cast. An attack or movement command may be input to use the second and third casts.<br><br>[[File:Heroic Swing.png|20px|link=]] {{sbc|First Cast:}} Fire a hook in the target direction that embeds in the first [[terrain]] hit for 2 seconds. ''''Heroic Swing''s'''' second cast can be used while the hook is attached. If the hook fails to attach or you become {{tip|immobilize|immobilized}}, {{tip|ground|grounded}}, or {{tip|polymorph|polymorphed}} within the duration, ''''Heroic Swing'''' is cancelled and placed on full cooldown.<br><br>[[File:Heroic Swing 2.png|20px|link=]] {{sbc|Second Cast:}} {{tip|dash|Swing}} around the terrain in either a clockwise or counterclockwise direction based on the position of the cursor {{tt|relative to your facing direction|Dash will move clockwise if the player''s cursor is anywhere to the left of their champion from their facing direction (or perspective), and counterclockwise if the cursor is anywhere to their champion''s right.}}, stopping upon colliding with an enemy champion or terrain. While swinging, fire at the nearest {{tip|sight|visible}} enemy within {{tip|cr|icononly=true}} 500 units every {{rutngt|0.2}} to deal them {{as|{{pp|15 to 75}}|physical damage}} {{as|(+ 15% AD)}} {{times}} {{as|(1 + {{fd|0.3}} per 100% ''''''bonus'''''' attack speed)}} {{as|physical damage}} and apply {{tip|on-hit}} effects for each shot, with on-hit damage reduced to 25% effectiveness. The dash will be {{tip|knockdown|interrupted}} if you are affected by any {{tip|immobilize|immobilizing}} or {{tip|polymorph|polymorphing}} crowd control during the dash.<br><br>{{sbc|Third Cast:}} End the swing by {{tip|dash|jumping}} to the target location and fire one last shot at a nearby {{tip|sight|visible}} enemy.<br><br>Scoring an enemy champion {{tip|takedown}} reduces ''''Heroic Swing''s'''' {{sti|''''''current'''''' cooldown}} to {{fd|0.5}} seconds.', 'Silver', NULL, NULL, TRUE),
(234, 'Spirit Infusion', 'Gain {{sti|hsp|{{as|10% heal and shield power}}}}. After casting your ultimate ability, increase your {{sti|hsp|{{as|heal and shield power|hsp}}}} by 50% for 10 seconds ({{sti|10 seconds cooldown}}).<br><br>''''Removed since [[V26.09]].''''', 'Silver', NULL, NULL, TRUE),
(235, 'Stuck In Here With Me', 'Casting your ultimate ability grants you an aura for 2 seconds, growing in size over the duration to up to {{sti|size|500 units}}. After the duration, you {{tip|taunt}} all enemies within the aura and gain 50% damage reduction for the same duration ({{sti|30 seconds cooldown}}). Additionally, gain {{sti|ability haste|{{as|30 ultimate haste|ability haste}}}}.<br><br>''''Aura is activated once the ultimate''s effect {{tt|starts|For instant-cast spells}} or has {{tt|elapsed|For duration-based spells}}.''''', 'Prismatic', NULL, '* On {{ci|Katarina}}, this augment will activate at the start of {{ais|R|Katarina}} channel.', TRUE),
(236, 'Symbiotic Mutation', 'Copy a random [[File:Augment.png|20px|icononly=true]] augment from your teammate upon selecting this augment and upon entering a new round''s ''''Shop Phase'''', with the copied augment changing every round.<br><br>''''This effect cannot grant you an augment that is not applicable to your champion.''''', 'Gold', 'symbioticmutation_large', '* You cannot get the same augment twice in a row.
        ** If there is only one augment you can get and you ''''Symbiotic Mutation'''' already copied it last round, you will gain ''''Augment 405'''' instead.
        * You gain the {{ii|Stat Bonus|Stat Bonus Anvils}} from ''''Stats!'''', ''''Stats on Stats'''' and ''''Stats on Stats on Stats!'''' every time ''''Symbiotic Mutation'''' copies one of those augments.
        * The first time ''''Symbiotic Mutation'''' copies ''''Gamba Anvil'''' you get {{g|1000}}, after that you only gain the cost reduction.', TRUE),
(237, 'Tank Engine', 'Scoring a champion {{tip|takedown}} permanently grants {{sti|{{as|''''''bonus maximum'''''' health}}}} and {{sti|size}}. This effect can be triggered only once per champion per round.', 'Gold', NULL, NULL, TRUE),
(238, 'Transmute: Chaos', 'Gain two completely random [[File:Augment.png|20px|icononly=true]] augments, excluding the other two offerings in your current assortment.', 'Prismatic', 'transmutechaos_large', NULL, TRUE),
(239, 'Transmute: Gold', 'Gain one random [[File:Augment.png|20px|icononly=true]] Gold augment, excluding the other two offerings in your current assortment.', 'Silver', 'transmutegold_large', NULL, TRUE),
(240, 'Transmute: Prismatic', 'Gain one random [[File:Augment.png|20px|icononly=true]] Prismatic augment, excluding the other two offerings in your current assortment.', 'Gold', 'transmuteprismatic_large', NULL, TRUE),
(241, 'Transmute: Silver', 'Gain completely random [[File:Augment.png|20px|icononly=true]] silver augments to fill all available slots.<br><br>You can no longer receive new augments, but replace or upgrade existing ones.', 'Prismatic', NULL, NULL, TRUE),
(242, 'Trash To Treasure', 'Gain a [[File:Augment.png|20px|icononly=true]] prismatic augment selection when this augment is removed or replaced.', 'Silver', NULL, NULL, TRUE),
(243, 'Trickster Demon', 'Upon exiting {{tip|stealth}}, unleash an explosion in a {{tip|cr|icononly=true}} 300 radius around you, dealing {{as|magic damage}} to nearby enemies. Upon your {{tip|clone|clones}} and traps being destroyed or expiring, they will also trigger this effect around them.', 'Gold', 'tricksterdemon_large', NULL, TRUE),
(244, 'Twin Fire', 'Damaging abilities against enemy champions launch {{as|Firecrackers|fury}} at the target that each deal {{as|{{pp|10 to 30}}|magic damage}} {{as|(+ 7% ''''''bonus'''''' AD)}} {{as|(+ 7% AP)}} {{as|magic damage}} ({{sti|5 seconds cooldown}}). Additionally, gain {{sti|{{as|25% critical strike chance}}}}.', 'Silver', NULL, NULL, TRUE),
(245, 'Undying Guard', 'Upon activating {{ais|Cultivation of War|Zaahen}} revive, deal {{as|75|physical damage}} {{as|(+ 100% AD)}} {{as|(+ 110% AP)}} {{as|(+ 15% of target''s ''''''current'''''' health)}} {{as|physical damage}} to nearby enemies and {{tip|airborne|knock back}} all targets hit up to {{tip|cr|icononly=true}} 700 units over {{fd|0.75}} seconds, as well as {{tip|stun|stunning}} them for the same duration.<br><br>For the next 4 seconds, gain {{sti|{{as|30% ''''''bonus'''''' movement speed}}}} and become {{tip|invulnerable}} against enemy {{tip|champions}} farther than {{tip|cr|icononly=true}} 450 units from yourself.<br><br>''''This augment is only available for {{ci|Zaahen}}.''''', 'Gold', NULL, NULL, TRUE),
(246, 'Unshackled', 'You can now cast {{cai|Hijack|Sylas}} on your ally to steal their {{tip|ability|ultimate ability}}. When you score a takedown, the ''''''total'''''' lockout duration on a single target and the ''''''total'''''' cooldown of your ultimate are reduced by {{sti|cooldown|20%}}. Gain {{sti|ability haste|{{as|60 ''''''Ultimate'''''' Haste|ability haste}}}}.<br><br>''''This augment is only available for {{ci|Sylas}}.''''', 'Gold', 'unshackled_large', NULL, TRUE),
(247, 'Unstable Transmutation', 'At the start of each round, this augment transforms into a random [[File:Augment.png|20px|icononly=true]] augment, either without levels or at its max level.', 'Gold', 'unstabletransmutation_large', NULL, TRUE),
(248, 'Upgrade Collector', 'Gain {{g|250}} on taking this augment. Upgrades {{ii|The Collector}}, empowering {{nie|Death}} to have its execution threshold increased by 1% each time you kill an enemy champion, capped at a threshold of {{sti|{{as|15% of the target''s ''''''maximum'''''' health}}}}, and {{nie|Taxes}} to generate higher gold from kills.', 'Silver', NULL, NULL, TRUE),
(249, 'Upgrade Hubris', 'Gain {{g|250}} on taking this augment. Upgrades {{ii|Hubris}}, empowering {{nie|Eminence}} to {{tip|heal}} you for {{as|5% ''''''maximum'''''' health}} + (1% per stack) {{as|''''''missing'''''' health}} upon being triggered and grant you {{sti|ms|{{as|10|ms}}}} (+ 5 per stack) {{as|''''''bonus'''''' movement speed}} for its duration.', 'Gold', NULL, NULL, TRUE),
(250, 'Upgrade Sword of Blossoming Dawn', 'Upgrades {{ii|Sword of Blossoming Dawn}}, empowering {{nie|Peppermint}} to have its {{sti|heal|healing}} increased by 250%. Additionally, you gain {{sti|{{as|100% ''''''bonus'''''' attack speed}}}}.', 'Prismatic', NULL, NULL, TRUE),
(251, 'Veil of Warding', 'Grants a {{tip|spell shield}} that blocks the next hostile ability {{sti|cooldown|every several seconds}} (cooldown timer does ''''''not'''''' restart from champion damage taken).', 'Silver', NULL, NULL, TRUE),
(252, 'Weighted Popoffs', 'Hitting an enemy champion with an ability generates a stack of {{as|Popoff|buzzword6}} for 6 seconds, stacking up to 6 times. For each stack, your basic abilities'' {{sti|cooldowns}} progress faster. At maximum {{as|Popoff|buzzword6}} stacks, this value is doubled.', 'Silver', NULL, NULL, TRUE),
(253, 'We''ll Be Right Back', 'Replaces {{si|Flee}} with ''''{{si|Time Stop}}''''.<br><br>[[File:Time Stop augment spell.png|20px|link=]] {{sbc|Time Stop:}} {{#invoke:SpellData|geteffect|Time Stop}}', 'Gold', 'wellberightback_large', NULL, TRUE),
(254, 'Wild Fire', '{{as|Automatically}} cast {{cai|Pyroclasm|Brand}} to an enemy champion within {{tip|cr|750}} units. The bouncing fireball deals {{as|magic damage}} to the target ({{sti|12 seconds cooldown}}). The fireball can bounce between you and enemy champions, up to several times.', 'Prismatic', NULL, NULL, TRUE),
(255, 'Wind Beneath Blade', 'Gain {{sti|{{as|{{fd|1.5}} ''''''bonus'''''' movement speed}}}} per 1 {{sti|{{as|Lethality}}}} or {{sti|{{as|flat magic penetration}}}}, and {{sti|{{as|5 ''''''bonus'''''' movement speed}}}} per 5% {{sti|{{as|armor penetration}}}} or {{sti|{{as|magic penetration}}}}.', 'Silver', NULL, NULL, TRUE),
(256, 'Zealot', 'Gain {{sti|attack speed|{{as|35%|as}}}} {{as|(+ 5% per 100 AP)}} {{as|''''''bonus'''''' attack speed}} and {{sti|critical strike chance|{{as|25%|critical strike chance}}}} {{as|(+ 5% per 100 AP)}} {{as|critical strike chance}} based on your {{sti|{{as|ability power}}}}.', 'Silver', NULL, NULL, TRUE);

